SELECT COUNT(song_id) AS song_count
FROM song_albums
WHERE album_id = 1;

SELECT user_id, song_id
FROM listening_history
WHERE playcount > 5;

SELECT SUM(playcount) AS total_playcount
FROM listening_history
WHERE user_id = 0 AND song_id = 0;

SELECT recommended_reason
FROM recommendations
WHERE user_id = 0;

SELECT COUNT(song_id) AS recommended_song_count
FROM recommendations
WHERE user_id = 0;

SELECT song_id, SUM(playcount) AS total_plays
FROM listening_history
WHERE song_id = 1;
